@pytest.mark.parametrize(
    ("type", "flag_value", "expected_default"),
    [
        (int, 2, 1),
        (str, "2", "True"),
    ],
)
def test_flag_default_and_activation(runner, type, flag_value, expected_default):
    @click.command()
    @click.option("--foo", flag_value=flag_value, default=True, type=type)
    def cli(foo):
        click.echo(foo)

    result = runner.invoke(cli, [])
    assert result.output == f"{expected_default}\n"

    result = runner.invoke(cli, ["--foo"])
    assert result.output == f"{flag_value}\n"


